import { Schema, model } from 'mongoose';

export interface User {
  id: string;
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const userSchema = new Schema<User>({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now }
});

export const UserModel = model<User>('User', userSchema);

export interface CreateUserDTO {
  username: string;
  password: string;
  email: string;
}

export interface UserResponseDTO {
  id: string;
  username: string;
  email: string;
  createdAt: Date;
}

import { z } from 'zod';

export const createUserSchema = z.object({
  username: z.string().min(3).max(30),
  password: z.string().min(6),
  email: z.string().email()
});

import { UserModel, User } from './user.model';

export class UserRepository {
  async createUser(user: Partial<User>): Promise<User> {
    const newUser = new UserModel(user);
    return newUser.save();
  }

  async findUserByUsername(username: string): Promise<User | null> {
    return UserModel.findOne({ username }).exec();
  }

  async findUserByEmail(email: string): Promise<User | null> {
    return UserModel.findOne({ email }).exec();
  }

  async findUserById(id: string): Promise<User | null> {
    return UserModel.findById(id).exec();
  }
}

import { UserRepository } from './user.repository';
import { CreateUserDTO, UserResponseDTO } from './user.dto';
import bcrypt from 'bcrypt';
import { AppError } from '../../global/error';

export class UserService {
  private userRepo = new UserRepository();

  async registerUser(dto: CreateUserDTO): Promise<UserResponseDTO> {
    const existsByUsername = await this.userRepo.findUserByUsername(dto.username);
    if (existsByUsername) {
      throw new AppError('Username already taken', 'USER_EXISTS', 400);
    }

    const existsByEmail = await this.userRepo.findUserByEmail(dto.email);
    if (existsByEmail) {
      throw new AppError('Email already in use', 'EMAIL_EXISTS', 400);
    }

    const passwordHash = await bcrypt.hash(dto.password, 10);
    const user = await this.userRepo.createUser({ ...dto, passwordHash });

    return {
      id: user.id,
      username: user.username,
      email: user.email,
      createdAt: user.createdAt
    };
  }
}

import { Request, Response, NextFunction } from 'express';
import { UserService } from './user.service';
import { createUserSchema } from './user.validator';

export class UserController {
  private userService = new UserService();

  async register(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const validatedData = createUserSchema.parse(req.body);
      const userDTO = await this.userService.registerUser(validatedData);
      res.status(201).json({ success: true, data: userDTO });
    } catch (error) {
      next(error);
    }
  }
}
